// ============== Main ==============
function main() {
  console.error('Loading ELF...');
  const elf = loadELF('/app/doomgeneric_mips');
  console.error(`Entry: 0x${elf.entry.toString(16)}`);

  const mem = new Memory();
  for (const seg of elf.segments) {
    console.error(`Seg: 0x${seg.vaddr.toString(16)} filesz=${seg.filesz} memsz=${seg.memsz}`);
    mem.loadSegment(seg.vaddr, elf.data, seg.offset, seg.filesz);
  }

  const STACK_TOP = 0x7FFF0000;
  const cpu = new CPU(mem, elf.entry);
  cpu.u[29] = STACK_TOP; // $sp
  cpu.heapEnd = 0x404b2000;

  try { fs.mkdirSync('/tmp', {recursive:true}); } catch(e) {}

  console.error('Running...');
  const t0 = Date.now();
  const exit = cpu.run();
  const dt = (Date.now() - t0) / 1000;
  console.error(`\nExit: ${exit}`);
  console.error(`${cpu.icount} insns in ${dt.toFixed(1)}s = ${Math.floor(cpu.icount/dt)} ips`);
}

main();
